mapper.update:
/** UsptTaskPrtcmpnyDao.update */
update uspt_task_prtcmpny
	 set    entrps_nm                 = #{entrpsNm}
			,rspnber_nm                = #{rspnberNm}
			,clsf_nm                   = #{clsfNm}
			,enc_telno                 = #{encTelno}
			,enc_mbtlnum               = #{encMbtlnum}
			,enc_email                 = #{encEmail}
			,tlsy_regist_no            = #{tlsyRegistNo}
			,member_id					=#{memberId}
			,updater_id                = #{updaterId}
			,updated_dt                = #{updatedDt}
where  task_partcptn_entrprs_id  = #{taskPartcptnEntrprsId}
  and	  bsns_plan_doc_id          = #{bsnsPlanDocId}

